&lt;/section&gt;


&lt;section class=&quot;block lighter-side&quot;&gt;
&lt;h4&gt;On the lighter side...&lt;/h4&gt;
	&lt;div class=&quot;blob&quot; style=&quot;text-align:center&quot;&gt;
	&lt;a href=&quot;https://bsky.app/profile/brucedlittle.bsky.social/post/3mbalkxdqps2r&quot; target=&quot;_blank&quot;&gt;
      &lt;img class=&quot;img-link&quot; alt=&quot;Yes, we&#39;re trafficking drugs. But we plan to buy a lot of Trump crypto with our money&quot; loading=&quot;lazy&quot; decoding=&quot;async&quot; style=&quot;--img-width:100vw&quot; src=&quot;/images/JytnI95duW-544.webp&quot; width=&quot;544&quot; height=&quot;524&quot;&gt;
	&lt;/a&gt;
&lt;/div&gt;
